define(["local_dsl_isp/pdfjs_loader","core/notification"],function(PdfjsLib,Notification){var pdfDoc=null,currentPage=1,currentScale=1.5,cfg={},rendering=false;var init=function(config){cfg=config;if(!PdfjsLib){showError("PDF.js library failed to load. Please refresh the page or contact support.");return}disableContextMenu();loadDocument();bindNavigation();bindZoom()};var loadDocument=function(){showLoading(true);hideError();var loadingTask=PdfjsLib.getDocument({url:cfg.serveUrl,withCredentials:true,isEvalSupported:false});loadingTask.promise.then(function(pdf){pdfDoc=pdf;var countEl=document.getElementById("dsl-isp-page-count");if(countEl){countEl.textContent=pdf.numPages}updateNavButtons();renderPage(1)}).catch(function(err){showLoading(false);showError(err.message||"Failed to load document.")})};var renderPage=function(pageNum){if(rendering){return}rendering=true;showLoading(true);pdfDoc.getPage(pageNum).then(function(page){var canvas=document.getElementById("dsl-isp-pdf-canvas");if(!canvas){rendering=false;return}var viewport=page.getViewport({scale:currentScale});canvas.height=viewport.height;canvas.width=viewport.width;var ctx=canvas.getContext("2d");var renderCtx={canvasContext:ctx,viewport:viewport};page.render(renderCtx).promise.then(function(){drawWatermark(ctx,canvas.width,canvas.height);currentPage=pageNum;var numEl=document.getElementById("dsl-isp-page-num");if(numEl){numEl.value=pageNum}updateNavButtons();showLoading(false);rendering=false}).catch(function(err){showLoading(false);rendering=false;showError(err.message||"Failed to render page.")})}).catch(function(err){showLoading(false);rendering=false;showError(err.message||"Failed to get page.")})};var drawWatermark=function(ctx,w,h){var lines=[cfg.viewerName||"",cfg.viewerEmail||"",cfg.tenantName||"",cfg.timestamp||"","Session #"+(cfg.sessionId||"")];var fontSize=Math.max(11,Math.round(w*0.018));var lineHeight=Math.round(fontSize*1.6);var blockHeight=lines.length*lineHeight;var tileX=Math.round(w*0.35);var tileY=Math.round(h*0.28);var angle=-(Math.PI/5.5);ctx.save();ctx.globalAlpha=0.12;ctx.fillStyle="#333333";ctx.font=fontSize+"px Arial, sans-serif";ctx.textAlign="center";ctx.textBaseline="middle";var startX=-tileX;var startY=-tileY;for(var tx=startX;tx<w+tileX*2;tx+=tileX){for(var ty=startY;ty<h+tileY*2;ty+=tileY){ctx.save();ctx.translate(tx,ty);ctx.rotate(angle);lines.forEach(function(line,i){var yOffset=(i*lineHeight)-(blockHeight/2)+(lineHeight/2);ctx.fillText(line,0,yOffset)});ctx.restore()}}ctx.restore()};var bindNavigation=function(){var prevBtn=document.getElementById("dsl-isp-prev-page");var nextBtn=document.getElementById("dsl-isp-next-page");var pageInput=document.getElementById("dsl-isp-page-num");if(prevBtn){prevBtn.addEventListener("click",function(){if(currentPage>1&&!rendering){renderPage(currentPage-1)}})}if(nextBtn){nextBtn.addEventListener("click",function(){if(pdfDoc&&currentPage<pdfDoc.numPages&&!rendering){renderPage(currentPage+1)}})}if(pageInput){pageInput.addEventListener("change",function(){var requested=parseInt(pageInput.value,10);if(pdfDoc&&requested>=1&&requested<=pdfDoc.numPages&&!rendering){renderPage(requested)}else{pageInput.value=currentPage}})}};var bindZoom=function(){var zoomInBtn=document.getElementById("dsl-isp-zoom-in");var zoomOutBtn=document.getElementById("dsl-isp-zoom-out");var fitWidthBtn=document.getElementById("dsl-isp-fit-width");if(zoomInBtn){zoomInBtn.addEventListener("click",function(){currentScale=Math.min(currentScale+0.25,4.0);if(pdfDoc&&!rendering){renderPage(currentPage)}})}if(zoomOutBtn){zoomOutBtn.addEventListener("click",function(){currentScale=Math.max(currentScale-0.25,0.5);if(pdfDoc&&!rendering){renderPage(currentPage)}})}if(fitWidthBtn){fitWidthBtn.addEventListener("click",function(){var container=document.getElementById("dsl-isp-canvas-container");if(container&&pdfDoc){pdfDoc.getPage(currentPage).then(function(page){var naturalViewport=page.getViewport({scale:1.0});currentScale=(container.clientWidth-20)/naturalViewport.width;if(!rendering){renderPage(currentPage)}})}})}};var updateNavButtons=function(){var prevBtn=document.getElementById("dsl-isp-prev-page");var nextBtn=document.getElementById("dsl-isp-next-page");if(prevBtn){prevBtn.disabled=(currentPage<=1)}if(nextBtn){nextBtn.disabled=(!pdfDoc||currentPage>=pdfDoc.numPages)}};var disableContextMenu=function(){var container=document.getElementById("dsl-isp-pdf-viewer");if(container){container.addEventListener("contextmenu",function(e){e.preventDefault();return false})}};var showLoading=function(show){var el=document.getElementById("dsl-isp-pdf-loading");if(el){if(show){el.classList.remove("d-none")}else{el.classList.add("d-none")}}};var showError=function(message){var el=document.getElementById("dsl-isp-pdf-error");if(el){el.textContent=message;el.classList.remove("d-none")}showLoading(false)};var hideError=function(){var el=document.getElementById("dsl-isp-pdf-error");if(el){el.classList.add("d-none");el.textContent=""}};return{init:init}});
